import { prepare, layoutNextLine } from '@chenglou/pretext';

const prepared = prepare(articleText, '16px Georgia');

// An image occupies the top-right corner
const IMAGE_LINES = 5;
const IMAGE_WIDTH = 200;
const FULL_WIDTH  = 600;

const lines = [];
let cursor = 0;
let lineIndex = 0;

while (cursor < articleText.length) {
  // First 5 lines are narrower to make room for the image
  const availableWidth = lineIndex < IMAGE_LINES
    ? FULL_WIDTH - IMAGE_WIDTH
    : FULL_WIDTH;

  const result = layoutNextLine(prepared, cursor, availableWidth);
  if (result === null) break;

  lines.push({ text: articleText.slice(cursor, result.endPos), width: result.width });
  cursor = result.endPos;
  lineIndex++;
}

import { prepare, layout, clearCache } from '@chenglou/pretext';

const FONT = '14px Inter';
const LINE_HEIGHT = 20;
const CONTAINER_WIDTH = 480;

// Prepare all items (batch the expensive step)
const prepared = items.map(item => prepare(item.text, FONT));

// Calculate all heights — fast, no DOM access
const heights = prepared.map(p =>
  layout(p, CONTAINER_WIDTH, LINE_HEIGHT).height
);

// Free memory after batch
clearCache();

import { VariableSizeList } from 'react-window';

<VariableSizeList
  height={600}
  itemCount={items.length}
  itemSize={index => heights[index]}
  width={CONTAINER_WIDTH}
>
  {({ index, style }) => (
    <div style={style}>{items[index].text}</div>
  )}
</VariableSizeList>
